import java.net.URI;
import java.util.Locale;

@Service
public class RedirectUriValidator {

    public boolean isAllowed(String redirectUri, String registeredBaseUrlPattern) {
        if (redirectUri == null || redirectUri.isBlank()) return false;
        if (registeredBaseUrlPattern == null || registeredBaseUrlPattern.isBlank()) return false;

        URI redir;
        URI base;
        try {
            redir = URI.create(redirectUri.trim());
            base = URI.create(registeredBaseUrlPattern.trim());
        } catch (Exception e) {
            return false;
        }

        if (redir.getScheme() == null || redir.getHost() == null) return false;
        if (base.getScheme() == null || base.getHost() == null) return false;

        String redirScheme = redir.getScheme().toLowerCase(Locale.ROOT);
        String baseScheme = base.getScheme().toLowerCase(Locale.ROOT);
        if (!redirScheme.equals(baseScheme)) return false;

        int redirPort = effectivePort(redir);
        int basePort = effectivePort(base);
        if (base.getPort() != -1 && redirPort != basePort) return false;

        String redirHost = normalizeHost(redir.getHost());
        String baseHost = normalizeHost(base.getHost());

        boolean wildcard = baseHost.startsWith("*.");
        if (wildcard) {
            String suffix = baseHost.substring(1);
            if (!(redirHost.endsWith(suffix) && redirHost.length() > suffix.length())) return false;
        } else {
            if (!redirHost.equals(baseHost)) return false;
        }

        String basePath = base.getPath();
        if (basePath == null || basePath.isEmpty()) basePath = "/";
        String redirPath = redir.getPath();
        if (redirPath == null || redirPath.isEmpty()) redirPath = "/";

        if (!redirPath.startsWith(basePath)) return false;

        String normalizedBaseUrl = base.getScheme() + "://" + base.getHost() + (base.getPort() == -1 ? "" : ":" + base.getPort()) + basePath;
        String normalizedRedirectUrl = redir.getScheme() + "://" + redir.getHost() + (redir.getPort() == -1 ? "" : ":" + redir.getPort()) + redirPath;

        return normalizedRedirectUrl.startsWith(normalizedBaseUrl);
    }

    private int effectivePort(URI uri) {
        if (uri.getPort() != -1) return uri.getPort();
        String scheme = uri.getScheme() == null ? "" : uri.getScheme().toLowerCase(Locale.ROOT);
        return scheme.equals("https") ? 443 : scheme.equals("http") ? 80 : -1;
    }

    private String normalizeHost(String host) {
        if (host == null) return null;
        String ascii = IDN.toASCII(host.trim(), IDN.ALLOW_UNASSIGNED);
        return ascii.toLowerCase(Locale.ROOT);
    }
}

